import 'dart:convert';
import 'dart:io';

/// Generates a bilingual EN-RU dictionary JSON file for LangVor.
///
/// Run with: dart run lib/tools/generate_dictionary.dart
void main() async {
  final entries = <Map<String, dynamic>>[];
  int rank = 1;

  // Core vocabulary organized by frequency and CEFR level
  for (final entry in _dictionaryData) {
    entries.add({
      'word': entry[0],
      'definition': entry[1],
      'partOfSpeech': entry[2],
      'russianTranslation': entry[3],
      'synonyms': entry[4],
      'frequencyRank': rank++,
      'cefrLevel': entry[5],
      'exampleSentence': entry[6],
    });
  }

  final json = const JsonEncoder.withIndent('  ').convert(entries);
  final file = File('assets/dictionary/en_ru_50k.json');
  await file.parent.create(recursive: true);
  await file.writeAsString(json);
  print('Generated ${entries.length} dictionary entries → ${file.path}');
}

